const body = $input.item.json.body;
const skill = body.skill;
const inputs = body.inputs || {};

const skills = {

  'board-deck': {
    system: `You are an expert at board-level communication. Write board decks with a clear narrative arc — situation, progress, challenges, asks. Boards want to know: are you in control, do you know what's working and what isn't, and what do you need from them. Be direct, use data, and never bury the lede. Output in clean markdown.`,
    user: `Create a board meeting presentation:

Company: ${inputs.company || ''}
Meeting date/quarter: ${inputs.quarter || ''}
Key metrics this period: ${inputs.metrics || ''}
Highlights (what went well): ${inputs.highlights || ''}
Challenges (what didn't): ${inputs.challenges || ''}
Strategic updates: ${inputs.strategy || ''}
Asks from the board: ${inputs.asks || 'none'}
Next period outlook: ${inputs.outlook || ''}

Output: slide-by-slide outline with speaker notes, narrative arc, key data callouts, and recommended visualizations (described in text).`
  },

  'customer-announcement': {
    system: `You are an expert in product marketing and customer communications. Write announcements that lead with customer benefit, not feature names. Adapt tone and length for each channel. Output in clean markdown with clearly labeled sections per channel.`,
    user: `Write customer announcements for this launch:

What's launching: ${inputs.launch || ''}
Key customer benefit: ${inputs.benefit || ''}
Who it's for: ${inputs.audience || 'all customers'}
Launch date: ${inputs.launch_date || ''}
Tone: ${inputs.tone || 'professional and warm'}
Channels needed: ${inputs.channels || 'email, in-app, social'}

Output: one version per channel (email subject + body, in-app message, social post), each optimized for that channel's format and length.`
  },

  'technical-spec': {
    system: `You are an expert technical product manager. Write technical specifications that give engineers everything they need to build without ambiguity. Include architecture decisions, data models, API designs, edge cases, and open questions. Output in clean markdown.`,
    user: `Write a technical specification:

Feature/system: ${inputs.feature || ''}
Problem being solved: ${inputs.problem || ''}
Proposed solution: ${inputs.solution || ''}
Tech stack: ${inputs.tech_stack || ''}
Constraints: ${inputs.constraints || ''}
Out of scope: ${inputs.out_of_scope || ''}

Output: overview, goals and non-goals, proposed architecture, data models, API design (endpoints, request/response), edge cases and error handling, open questions, and implementation notes.`
  },

  'decision-doc': {
    system: `You are an expert at structured decision-making. Write decision documents using the DACI framework (Driver, Approver, Contributor, Informed) with clear options analysis and a defensible recommendation. Never recommend without showing your reasoning. Output in clean markdown.`,
    user: `Write a decision document:

Decision to make: ${inputs.decision || ''}
Context and background: ${inputs.context || ''}
Options being considered: ${inputs.options || ''}
Key constraints: ${inputs.constraints || ''}
Stakeholders: ${inputs.stakeholders || ''}
Deadline for decision: ${inputs.deadline || ''}

Output: decision statement, context, DACI, options analysis (pros/cons/risks per option), recommendation with rationale, implementation plan, and open questions.`
  },

  'exec-update': {
    system: `You are an expert at executive communication. Write crisp executive updates using the SCQA framework (Situation, Complication, Question, Answer). Executives want the bottom line first, then supporting evidence. Cut everything that doesn't serve the narrative. Output in clean markdown.`,
    user: `Create an executive update:

Topic: ${inputs.topic || ''}
Audience: ${inputs.audience || 'leadership team'}
Situation (current state): ${inputs.situation || ''}
Complication (what changed or is at risk): ${inputs.complication || ''}
Key data points: ${inputs.data || ''}
Recommended action or ask: ${inputs.ask || ''}

Output: SCQA-structured update (max 1 page equivalent), key metrics callout box, recommended next steps, and an optional appendix outline for supporting details.`
  },

  'api-docs': {
    system: `You are an expert technical writer specializing in API documentation. Write clear, complete API docs with authentication, all endpoints, request/response examples, error codes, and rate limits. Use realistic example values. Output in clean markdown.`,
    user: `Write API documentation:

API name: ${inputs.api_name || ''}
Purpose: ${inputs.purpose || ''}
Authentication method: ${inputs.auth || ''}
Endpoints to document: ${inputs.endpoints || ''}
Base URL: ${inputs.base_url || ''}
Audience: ${inputs.audience || 'external developers'}

Output: overview, authentication guide, endpoint reference (method, path, description, parameters, request body, response, errors, example), rate limits, and error code reference table.`
  },

  'sales-enablement': {
    system: `You are an expert in product marketing and sales enablement. Create complete sales enablement packages that give reps everything they need to sell confidently — positioning, objection handling, competitive comparisons, and talk tracks. Output in clean markdown.`,
    user: `Create a sales enablement kit:

Product/feature: ${inputs.product || ''}
Target buyer: ${inputs.buyer || ''}
Key differentiators: ${inputs.differentiators || ''}
Main competitors: ${inputs.competitors || ''}
Common objections: ${inputs.objections || ''}
Ideal customer profile: ${inputs.icp || ''}

Output: one-pager summary, elevator pitch (30 sec), discovery questions, full talk track, objection handling guide (objection + response for each), competitive battle card, and qualification checklist.`
  }

};

const skill_config = skills[skill];
if (!skill_config) {
  throw new Error(`Unknown skill: "${skill}". Valid options: ${Object.keys(skills).join(', ')}`);
}

return {
  skill: skill,
  system_prompt: skill_config.system,
  user_message: skill_config.user
};

const raw = $input.item.json;
const content = raw.content && raw.content[0] ? raw.content[0].text : '';
const skill = $('Build Prompt').item.json.skill;
return {
  skill: skill,
  content: content,
  word_count: content.split(/\s+/).filter(w => w).length,
  generated_at: new Date().toISOString()
};
